using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9: Default discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator" — preserve old name for compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id values no longer include the discriminator prefix.
            // Existing documents have id format "Product|123" — preserve old format.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // EF Core 9: HasIndex throws for Cosmos entities. Removed — manage indexing
        // via the container's indexing policy in Azure Portal / Bicep / Terraform.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } = null!; }

